import { RaftNode, RaftConfig, RPCResponse } from 'raftjs';
import { blake2bAsHex } from 'blakejs';
import { LogEntry } from './log';

export class EnhancedRaftNode extends RaftNode {
  private readonly preVoteResponseQuorumThreshold: number;
  private candidateNodeId: string | null = null;
  private voteGrantedBitmask: number = 0;

  constructor(config: RaftConfig) {
    super(config);
    this.preVoteResponseQuorumThreshold = Math.floor(config.peerCount / 2) + 1;
  }

  async startElectionIfNeeded(): Promise<void> {
    if (this.state !== 'follower') return;
    const partitionSuspected = await this.detectNetworkPartition();
    if (partitionSuspected) {
      const preVoteSuccess = await this.runPreVotePhase();
      if (!preVoteSuccess) {
        return;
      }
    }
    super.startElection();
  }

  private async detectNetworkPartition(): Promise<boolean> {
    const heartbeatResponses = await this.sendHeartbeatsToPeers();
    const failedCount = heartbeatResponses.reduce(
      (acc, resp) => acc + (resp.success ? 0 : 1),
      0,
    );
    return failedCount > this.peerCount / 2;
  }

  private async runPreVotePhase(): Promise<boolean> {
    this.candidateNodeId = this.nodeId;
    this.voteGrantedBitmask = 0;
    const preVoteRequests = this.peers.map(peer =>
      this.sendPreVoteRequest(peer),
    );
    const responses = await Promise.all(preVoteRequests);
    responses.forEach((resp, idx) => {
      if (resp.voteGranted) {
        this.voteGrantedBitmask |= 1 << idx;
      }
    });
    const grantedCount = BitCount(this.voteGrantedBitmask);
    return grantedCount >= this.preVoteResponseQuorumThreshold;
  }

  private async sendPreVoteRequest(peer: string): Promise<{ voteGranted: boolean }> {
    const term = this.currentTerm + 1;
    const lastLog = this.log.getLastEntry();
    const payload = {
      term,
      candidateId: this.nodeId,
      lastLogIndex: lastLog?.index ?? 0,
      lastLogTerm: lastLog?.term ?? 0,
    };
    const rpcResp: RPCResponse = await this.rpc.sendRequestVote(
      peer,
      payload,
    );
    return { voteGranted: rpcResp.voteGranted ?? false };
  }

  // Helper: count set bits using Brian Kernighan’s algorithm
  private static BitCount(x: number): number {
    let count = 0;
    while (x) {
      x &= x - 1;
      count++;
    }
    return count;
  }
}
